/**
 * DeepSeek 官方 API 供应商适配
 * @version 2.0
 */

// ============================================================
// 类型定义
// ============================================================

type VideoMode =
  | "singleImage"
  | "startEndRequired"
  | "endFrameOptional"
  | "startFrameOptional"
  | "text"
  | (`videoReference:${number}` | `imageReference:${number}` | `audioReference:${number}`)[];

interface TextModel {
  name: string;
  modelName: string;
  type: "text";
  think: boolean;
}

interface ImageModel {
  name: string;
  modelName: string;
  type: "image";
  mode: ("text" | "singleImage" | "multiReference")[];
  associationSkills?: string;
}

interface VideoModel {
  name: string;
  modelName: string;
  type: "video";
  mode: VideoMode[];
  associationSkills?: string;
  audio: "optional" | false | true;
  durationResolutionMap: { duration: number[]; resolution: string[] }[];
}

interface TTSModel {
  name: string;
  modelName: string;
  type: "tts";
  voices: { title: string; voice: string }[];
}

interface VendorConfig {
  id: string;
  version: string;
  name: string;
  author: string;
  description?: string;
  icon?: string;
  inputs: { key: string; label: string; type: "text" | "password" | "url"; required: boolean; placeholder?: string }[];
  inputValues: Record<string, string>;
  models: (TextModel | ImageModel | VideoModel | TTSModel)[];
}

interface ImageConfig {
  prompt: string;
  imageBase64: string[];
  size: "1K" | "2K" | "4K";
  aspectRatio: `${number}:${number}`;
}

interface VideoConfig {
  duration: number;
  resolution: string;
  aspectRatio: "16:9" | "9:16";
  prompt: string;
  imageBase64?: string[];
  audio?: boolean;
  mode: VideoMode[];
}

interface TTSConfig {
  text: string;
  voice: string;
  speechRate: number;
  pitchRate: number;
  volume: number;
}

// ============================================================
// 全局声明
// ============================================================

declare const fetch: any;
declare const createDeepSeek: any;
declare const exports: {
  vendor: VendorConfig;
  textRequest: (m: TextModel, t: boolean, tl: 0 | 1 | 2 | 3) => any;
  imageRequest: (c: ImageConfig, m: ImageModel) => Promise<string>;
  videoRequest: (c: VideoConfig, m: VideoModel) => Promise<string>;
  ttsRequest: (c: TTSConfig, m: TTSModel) => Promise<string>;
  checkForUpdates?: () => Promise<{ hasUpdate: boolean; latestVersion: string; notice: string }>;
  updateVendor?: () => Promise<string>;
};

// ============================================================
// 供应商配置
// ============================================================

const vendor: VendorConfig = {
  id: "deepseek",
  version: "2.0",
  author: "Toonflow",
  name: "DeepSeek 官方 API",
  description:
    "DeepSeek 官方 OpenAI 兼容接口。默认地址为 https://api.deepseek.com 。支持官方文档中的思考模式（thinking）与思考强度（reasoning_effort）。\n\n兼容旧模型名 deepseek-chat / deepseek-reasoner，但官方文档已标注为弃用别名。",
  icon: "",
  inputs: [
    { key: "apiKey", label: "API密钥", type: "password", required: true },
    { key: "baseUrl", label: "请求地址", type: "url", required: true, placeholder: "示例：https://api.deepseek.com" },
  ],
  inputValues: {
    apiKey: "",
    baseUrl: "https://api.deepseek.com",
  },
  models: [
    { name: "DeepSeek-V4-Flash", modelName: "deepseek-v4-flash", type: "text", think: false },
    { name: "DeepSeek-V4-Flash-Think", modelName: "deepseek-v4-flash(thinking)", type: "text", think: true },
    { name: "DeepSeek-V4-Pro", modelName: "deepseek-v4-pro", type: "text", think: false },
    { name: "DeepSeek-V4-Pro-Think", modelName: "deepseek-v4-pro(thinking)", type: "text", think: true },
    { name: "DeepSeek-Chat(兼容旧名)", modelName: "deepseek-chat", type: "text", think: false },
    { name: "DeepSeek-Reasoner(兼容旧名)", modelName: "deepseek-reasoner", type: "text", think: true },
  ],
};

// ============================================================
// 辅助工具
// ============================================================

const getApiKey = () => {
  if (!vendor.inputValues.apiKey) throw new Error("缺少 API Key");
  return String(vendor.inputValues.apiKey).replace(/^(Bearer|Token)\s+/i, "").trim();
};

const getBaseUrl = () => {
  return String(vendor.inputValues.baseUrl || "https://api.deepseek.com")
    .trim()
    .replace(/\/+$/g, "")
    .replace(/\/v1$/i, "");
};

const resolveModelId = (modelName: string) => {
  return String(modelName || "").replace(/\((thinking|reasoning)\)$/i, "");
};

const resolveReasoningEffort = (thinkLevel: 0 | 1 | 2 | 3) => {
  return thinkLevel >= 3 ? "max" : "high";
};

// ============================================================
// 适配器函数
// ============================================================

const textRequest = (model: TextModel, think: boolean, thinkLevel: 0 | 1 | 2 | 3) => {
  const apiKey = getApiKey();
  const baseURL = getBaseUrl();
  const apiModelName = resolveModelId(model.modelName);
  const thinkingEnabled = think ?? !!model.think;

  return createDeepSeek({
    apiKey,
    baseURL,
    fetch: async (url: string, options?: any) => {
      let rawBody: Record<string, any> = {};
      if (typeof options?.body === "string") {
        try {
          rawBody = JSON.parse(options.body);
        } catch {
          rawBody = {};
        }
      }

      const body: Record<string, any> = {
        ...rawBody,
        model: apiModelName,
        thinking: {
          type: thinkingEnabled ? "enabled" : "disabled",
        },
      };

      if (thinkingEnabled) {
        body.reasoning_effort = resolveReasoningEffort(thinkLevel);
        delete body.temperature;
        delete body.top_p;
        delete body.presence_penalty;
        delete body.frequency_penalty;
      } else {
        delete body.reasoning_effort;
      }

      return fetch(url, {
        ...options,
        body: JSON.stringify(body),
      });
    },
  }).chat(apiModelName);
};

const imageRequest = async (_config: ImageConfig, _model: ImageModel): Promise<string> => {
  throw new Error("DeepSeek 官方 API 当前接入为文本模型，未实现图片模型。");
};

const videoRequest = async (_config: VideoConfig, _model: VideoModel): Promise<string> => {
  throw new Error("DeepSeek 官方 API 当前接入为文本模型，未实现视频模型。");
};

const ttsRequest = async (_config: TTSConfig, _model: TTSModel): Promise<string> => {
  throw new Error("DeepSeek 官方 API 当前接入为文本模型，未实现语音模型。");
};

const checkForUpdates = async (): Promise<{ hasUpdate: boolean; latestVersion: string; notice: string }> => {
  return { hasUpdate: false, latestVersion: "2.0", notice: "" };
};

const updateVendor = async (): Promise<string> => {
  return "";
};

// ============================================================
// 导出
// ============================================================

exports.vendor = vendor;
exports.textRequest = textRequest;
exports.imageRequest = imageRequest;
exports.videoRequest = videoRequest;
exports.ttsRequest = ttsRequest;
exports.checkForUpdates = checkForUpdates;
exports.updateVendor = updateVendor;

export {};

