type ReferenceList = { type: "image"; base64: string } | { type: "audio"; base64: string } | { type: "video"; base64: string };

const ratioSizeMap: Record<string, string> = {
  "16:9": "1280x720",
  "9:16": "720x1280",
  "1:1": "1024x1024",
  "3:2": "1792x1024",
  "2:3": "1024x1792",
};

const toImageSize = (aspectRatio?: string) => ratioSizeMap[aspectRatio || ""] || "1024x1024";

const toVideoSize = (aspectRatio?: string) => {
  if (aspectRatio === "16:9") return "1280x720";
  if (aspectRatio === "1:1") return "1024x1024";
  return "720x1280";
};

const toVideoSeconds = (duration?: number) => {
  const value = Number(duration || 6);
  if (value <= 6) return 6;
  if (value <= 10) return 10;
  if (value <= 12) return 12;
  if (value <= 16) return 16;
  return 20;
};

const toVideoResolution = (resolution?: string) => (String(resolution || "720p").toLowerCase() === "480p" ? "480p" : "720p");

const toDataImageUrl = (value: string) => {
  if (/^data:image\//i.test(value)) return value;
  if (/^https?:\/\//i.test(value) || /^asset:\/\//i.test(value)) return value;
  return `data:image/png;base64,${value}`;
};

const getImageReferences = (config: { referenceList?: Extract<ReferenceList, { type: "image" }>[]; imageBase64?: string[] }) => {
  const refs = config.referenceList?.length ? config.referenceList.map((item) => item.base64) : config.imageBase64 || [];
  return refs.filter(Boolean).map(toDataImageUrl);
};

const readJsonResponse = async (response: any) => {
  const text = await response.text();
  let data: any = null;
  try {
    data = text ? JSON.parse(text) : null;
  } catch {
    throw new Error(`接口返回非JSON内容：${text.slice(0, 500)}`);
  }
  if (!response.ok || data?.error) {
    const message = data?.error?.message || data?.message || text;
    throw new Error(`请求失败，状态码: ${response.status}, 错误信息: ${message}`);
  }
  return data;
};

const extractMarkdownMedia = (content: string) => {
  const match = content.match(/!\[[^\]]*]\(([^)]+)\)/);
  return (match?.[1] || content || "").trim();
};

const extractImageResult = async (data: any) => {
  const item = data?.data?.[0];
  if (item?.b64_json) return item.b64_json;
  if (item?.url) return await urlToBase64(item.url);
  const content = data?.choices?.[0]?.message?.content;
  if (typeof content === "string" && content.trim()) {
    const value = extractMarkdownMedia(content);
    if (/^data:image\//i.test(value)) return value;
    if (/^https?:\/\//i.test(value)) return await urlToBase64(value);
    return value;
  }
  throw new Error("模型返回成功，但未找到图片数据");
};

//图片请求函数
interface ImageConfig {
  prompt: string; //图片提示词
  referenceList?: Extract<ReferenceList, { type: "image" }>[];
  imageBase64?: string[]; //输入的图片提示词
  size: "1K" | "2K" | "4K"; // 图片尺寸
  aspectRatio: `${number}:${number}`; // 长宽比
}
const imageRequest = async (imageConfig: ImageConfig, imageModel: ImageModel) => {
  const baseUrl = getBaseUrl();
  const imageRefs = getImageReferences(imageConfig);

  if (imageModel.modelName === "grok-imagine-image-edit") {
    if (!imageRefs.length) throw new Error("Grok Imagine Image Edit 需要至少一张参考图");
    const content: any[] = [{ type: "text", text: imageConfig.prompt }];
    for (const image of imageRefs.slice(-5)) {
      content.push({ type: "image_url", image_url: { url: image } });
    }
    const response = await fetch(`${baseUrl}/chat/completions`, {
      method: "POST",
      headers: getJsonHeaders(),
      body: JSON.stringify({
        model: imageModel.modelName,
        messages: [{ role: "user", content }],
        image_config: {
          n: 1,
          size: "1024x1024",
          response_format: "b64_json",
        },
        stream: false,
      }),
    });
    return await extractImageResult(await readJsonResponse(response));
  }

  if (imageRefs.length) {
    throw new Error("当前 Grok 生图模型不支持参考图，请选择 Grok Imagine Image Edit");
  }

  const response = await fetch(`${baseUrl}/images/generations`, {
    method: "POST",
    headers: getJsonHeaders(),
    body: JSON.stringify({
      model: imageModel.modelName,
      prompt: imageConfig.prompt,
      n: 1,
      size: toImageSize(imageConfig.aspectRatio),
      response_format: "b64_json",
    }),
  });
  return await extractImageResult(await readJsonResponse(response));
};
exports.imageRequest = imageRequest;

interface VideoConfig {
  duration: number;
  resolution: string;
  aspectRatio: "16:9" | "9:16";
  prompt: string;
  referenceList?: ReferenceList[];
  imageBase64?: string[];
  audio?: boolean;
  mode:
    | "singleImage" // 单图
    | "multiImage" // 多图模式
    | "gridImage" // 网格单图（传入一张图片，但该图片是网格图）
    | "startEndRequired" // 首尾帧（两张都得有）
    | "endFrameOptional" // 首尾帧（尾帧可选）
    | "startFrameOptional" // 首帧可选
    | "text" // 文本生视频
    | ("video" | "image" | "audio" | "text")[]; // 混合参考
}

const dataImageToFile = (dataUrl: string, index: number) => {
  const value = toDataImageUrl(dataUrl);
  const match = value.match(/^data:(image\/[^;]+);base64,(.+)$/i);
  if (!match) return null;
  const mime = match[1] || "image/png";
  const ext = mime.includes("jpeg") || mime.includes("jpg") ? "jpg" : mime.includes("webp") ? "webp" : "png";
  return {
    buffer: Buffer.from(match[2], "base64"),
    filename: `reference-${index + 1}.${ext}`,
    contentType: mime,
  };
};

const videoRequest = async (videoConfig: VideoConfig, videoModel: VideoModel) => {
  const baseUrl = getBaseUrl();
  const form = new FormData();
  form.append("model", videoModel.modelName);
  form.append("prompt", videoConfig.prompt);
  form.append("seconds", String(toVideoSeconds(videoConfig.duration)));
  form.append("size", toVideoSize(videoConfig.aspectRatio));
  form.append("resolution_name", toVideoResolution(videoConfig.resolution));
  form.append("preset", "custom");

  const imageRefs = videoConfig.referenceList?.length
    ? videoConfig.referenceList.filter((item) => item.type === "image").map((item) => item.base64)
    : videoConfig.imageBase64 || [];
  imageRefs.slice(0, 5).forEach((image, index) => {
    const file = dataImageToFile(image, index);
    if (file) {
      form.append("input_reference[]", file.buffer, {
        filename: file.filename,
        contentType: file.contentType,
      });
    } else {
      logger(`Grok 视频参考图 ${index + 1} 不是可上传的 base64 图片，已跳过`);
    }
  });

  const createResponse = await axios.post(`${baseUrl}/videos`, form, {
    headers: {
      Authorization: `Bearer ${getApiKey()}`,
      ...form.getHeaders(),
    },
    maxBodyLength: Infinity,
    maxContentLength: Infinity,
  });
  const videoId = createResponse.data?.id;
  if (!videoId) throw new Error("视频生成任务创建失败：未返回任务ID");

  const pollResult = await pollTask(
    async () => {
      const response = await fetch(`${baseUrl}/videos/${videoId}`, {
        headers: { Authorization: `Bearer ${getApiKey()}` },
      });
      const data = await readJsonResponse(response);
      logger(`[Grok 视频生成] 任务状态: ${data.status}, 进度: ${data.progress ?? 0}%`);
      if (data.status === "completed") return { completed: true, data: videoId };
      if (data.status === "failed") return { completed: true, error: data.error?.message || "视频生成失败" };
      return { completed: false };
    },
    5000,
    1800000,
  );

  if (pollResult.error) throw new Error(pollResult.error);

  const contentResponse = await fetch(`${baseUrl}/videos/${videoId}/content`, {
    headers: { Authorization: `Bearer ${getApiKey()}` },
  });
  if (!contentResponse.ok) {
    const text = await contentResponse.text();
    throw new Error(`视频下载失败，状态码: ${contentResponse.status}, 错误信息: ${text}`);
  }
  return Buffer.from(await contentResponse.arrayBuffer()).toString("base64");
};
exports.videoRequest = videoRequest;

interface TTSConfig {
  text: string;
  voice: string;
  speechRate: number;
  pitchRate: number;
  volume: number;
}
const ttsRequest = async (ttsConfig: TTSConfig, ttsModel: TTSModel) => {
  return null;
};
exports.ttsRequest = ttsRequest;

export {};

