/**
 * 生成可灵AI的JWT鉴权Token
 */
const generateAuthToken = (): string => {
  const accessKey = String(
    vendor.inputValues.accessKey || vendor.inputValues.apiKey || vendor.inputValues.ak || vendor.inputValues.access_key || "",
  ).trim();
  const secretKey = String(
    vendor.inputValues.secretKey || vendor.inputValues.sk || vendor.inputValues.secret_key || vendor.inputValues.apiSecret || "",
  ).trim();
  if (!accessKey) throw new Error("缺少 AccessKey");
  if (!secretKey) throw new Error("缺少 SecretKey");
  const now = Math.floor(Date.now() / 1000);
  const payload = {
    iss: accessKey,
    exp: now + 1800,
    nbf: now - 5,
  };
  return jsonwebtoken.sign(payload, secretKey, {
    algorithm: "HS256",
    header: { alg: "HS256", typ: "JWT" },
  });
};

/**
 * 获取基础请求地址
 */
const getBaseUrl = (): string => {
  return String(vendor.inputValues.baseUrl || "https://api-beijing.klingai.com").trim().replace(/\/+$/, "") || "https://api-beijing.klingai.com";
};

/**
 * 从 ReferenceList 条目中提取可用的数据字符串
 * 对于 url 类型返回 url，对于 base64 类型返回纯 base64（去掉 data: 前缀）
 */
const extractRawBase64 = (ref: ReferenceList): string => {
  return ref.base64.replace(/^data:[^;]+;base64,/, "");
};

/**
 * 从 ReferenceList 条目中提取带头的 base64 或 url
 * 用于 omni-video 接口，该接口的 image_url 支持带前缀的 base64 和 url
 */
const extractImageUrl = (ref: ReferenceList): string => {
  return ref.base64.startsWith("http://") || ref.base64.startsWith("https://") ? ref.base64 : ref.base64.replace(/^data:[^;]+;base64,/, "");
};

const MAX_KLING_IMAGE_BYTES = 1024 * 1024;
const MAX_KLING_VIDEO_PROMPT_LENGTH = 2500;
const MAX_KLING_OMNI_ELEMENTS = 7;

const getTextLength = (value: string): number => Array.from(value).length;

const limitKlingVideoPrompt = (value: string | undefined | null): string => {
  const text = String(value || "").trim();
  if (!text) return "";
  if (getTextLength(text) <= MAX_KLING_VIDEO_PROMPT_LENGTH) return text;

  const clipped = Array.from(text).slice(0, MAX_KLING_VIDEO_PROMPT_LENGTH).join("");
  const minReadableCut = Math.floor(MAX_KLING_VIDEO_PROMPT_LENGTH * 0.9);
  const separators = ["\n\n", "\n", "。", ".", "；", ";", "，", ","];
  let cutIndex = -1;
  for (const separator of separators) {
    const index = clipped.lastIndexOf(separator);
    if (index >= minReadableCut) {
      cutIndex = index + separator.length;
      break;
    }
  }

  const nextPrompt = (cutIndex > 0 ? clipped.slice(0, cutIndex) : clipped).trim() || clipped;
  logger(`[videoRequest] 可灵视频提示词超出 ${MAX_KLING_VIDEO_PROMPT_LENGTH} 字符，已截断：${getTextLength(text)} -> ${getTextLength(nextPrompt)}`);
  return nextPrompt;
};

const limitKlingOmniElements = <T>(items: T[], label: string): T[] => {
  if (items.length <= MAX_KLING_OMNI_ELEMENTS) return items;
  logger(`[videoRequest] 可灵 Omni ${label}数量超出 ${MAX_KLING_OMNI_ELEMENTS} 个，已截断：${items.length} -> ${MAX_KLING_OMNI_ELEMENTS}`);
  return items.slice(0, MAX_KLING_OMNI_ELEMENTS);
};

const normalizeImageInput = async (ref: ReferenceList): Promise<string> => {
  if (ref.base64.startsWith("http://") || ref.base64.startsWith("https://")) return ref.base64;
  if (!ref.base64.startsWith("data:")) return ref.base64;

  let nextValue = ref.base64;
  const base64Body = ref.base64.replace(/^data:[^;]+;base64,/, "");
  const approxBytes = Math.floor((base64Body.length * 3) / 4);
  if (approxBytes > MAX_KLING_IMAGE_BYTES) {
    nextValue = await zipImage(ref.base64, MAX_KLING_IMAGE_BYTES);
  }
  return nextValue.replace(/^data:[^;]+;base64,/, "");
};

const extractTaskId = (payload: any) => payload?.data?.task_id || payload?.task_id || payload?.data?.id || payload?.id || "";

const extractTaskStatus = (payload: any) =>
