const extractTaskError = (payload: any) =>
  payload?.data?.task_status_msg ||
  payload?.task_status_msg ||
  payload?.data?.fail_reason ||
  payload?.fail_reason ||
  payload?.message ||
  payload?.error?.message ||
  payload?.error ||
  "";

const extractVideoResult = (payload: any) =>
  payload?.data?.task_result?.videos?.[0]?.url ||
  payload?.task_result?.videos?.[0]?.url ||
  payload?.data?.videos?.[0]?.url ||
  payload?.videos?.[0]?.url ||
  payload?.data?.result_url ||
  payload?.result_url ||
  "";

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

const isRetryableStatus = (status: number) => [408, 409, 425, 429, 500, 502, 503, 504].includes(Number(status));

const retryableNetworkCodes = ["ECONNRESET", "ETIMEDOUT", "ECONNABORTED", "EAI_AGAIN", "ENETUNREACH", "EHOSTUNREACH"];

const isRetryableNetworkError = (error: any) => {
  const code = String(error?.code || error?.cause?.code || "").toUpperCase();
  const message = String(error?.message || error?.cause?.message || "").toLowerCase();
  return (
    retryableNetworkCodes.includes(code) ||
    message.includes("socket hang up") ||
    message.includes("connection reset") ||
    message.includes("econnreset") ||
    message.includes("network timeout")
  );
};

const getRetryDelay = (attempt: number) => Math.min(30000, 1500 * Math.pow(2, attempt - 1));

const formatRequestError = (status: number, data: any, url: string) => {
  if (data?.code === 1201 && String(data?.message || "").toLowerCase() === "model is not supported") {
    return "当前可灵账号/区域不支持该模型，请检查接口地址、模型权限或账号套餐";
  }
  return `请求失败，状态码: ${status}, URL: ${url}, 错误信息: ${JSON.stringify(data)}`;
};

const requestJson = async (method: "GET" | "POST", url: string, token: string, body?: any, retries = 6) => {
  let lastError: Error | null = null;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await axios({
        method,
        url,
        data: body,
        timeout: method === "POST" ? 180000 : 45000,
        maxRedirects: 5,
        validateStatus: () => true,
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
      });
      const data = response?.data ?? {};
      if (response.status >= 200 && response.status < 300) {
        return data;
      }
      const message = formatRequestError(response.status, data, url);
      if (attempt < retries && isRetryableStatus(response.status)) {
        lastError = new Error(message);
        const delay = getRetryDelay(attempt);
        logger(`可灵AI请求失败，${delay}ms 后重试 (${attempt}/${retries}): ${message}`);
        await sleep(delay);
        continue;
      }
      const error: any = new Error(message);
      error.status = response.status;
      error.data = data;
      throw error;
    } catch (error: any) {
      const status = error?.status || error?.response?.status;
      const data = error?.data || error?.response?.data;
      const message =
        status && data
          ? formatRequestError(status, data, url)
          : `请求异常, URL: ${url}, 错误: ${error?.message || error?.code || "unknown"}${error?.cause?.message ? `, 原因: ${error.cause.message}` : ""}`;
      const shouldRetry = status ? isRetryableStatus(status) : isRetryableNetworkError(error);
      if (attempt < retries && shouldRetry) {
        lastError = new Error(message);
        const delay = getRetryDelay(attempt);
        logger(`可灵AI请求异常，${delay}ms 后重试 (${attempt}/${retries}): ${message}`);
        await sleep(delay);
        continue;
      }
      if (lastError && attempt >= retries) {
        throw new Error(`${message}；已重试 ${retries} 次仍失败，请稍后重试或降低并发/参考图数量`);
      }
      throw new Error(message);
    }
  }
  throw lastError || new Error("请求失败");
};

type ResolvedModel = { modelName: string; mode: string; legacyMultiRef: boolean };

const resolveLegacyModelName = (rawModelName: string): ResolvedModel => {
  const normalizedName = String(rawModelName || "").trim();
  const legacyMultiRef = /-multi-image$/i.test(normalizedName);

  const legacyMatch = normalizedName.match(/^(.*)-(std|pro)(?:-\d+s)?(?:-multi-image)?$/i);
  if (legacyMatch?.[1] && legacyMatch?.[2]) {
    return {
      modelName: legacyMatch[1],
      mode: legacyMatch[2].toLowerCase(),
      legacyMultiRef,
    };
  }

  const masterMatch = normalizedName.match(/^(.*-master)(?:-\d+s)?$/i);
  if (masterMatch?.[1]) {
    return {
      modelName: masterMatch[1],
      mode: "pro",
      legacyMultiRef,
    };
  }

  const colonIndex = normalizedName.indexOf(":");
  if (colonIndex > -1) {
    return {
      modelName: normalizedName.slice(0, colonIndex),
      mode: normalizedName.slice(colonIndex + 1) || "pro",
      legacyMultiRef,
    };
  }

  return {
    modelName: normalizedName,
    mode: "pro",
    legacyMultiRef,
  };
};

/**
 * 提交任务并轮询获取结果的通用函数
 */
const submitAndPoll = async (submitUrl: string, queryUrlBase: string, requestBody: any): Promise<string> => {
  logger(`开始提交可灵AI视频生成任务: ${submitUrl}`);
  logger(
    `请求参数: ${JSON.stringify({
      ...requestBody,
      image: requestBody.image ? "[BASE64]" : undefined,
      image_tail: requestBody.image_tail ? "[BASE64]" : undefined,
      image_list: requestBody.image_list ? "[IMAGES]" : undefined,
    })}`,
  );
  const submitData = await requestJson("POST", submitUrl, generateAuthToken(), requestBody, 6);
  const taskId = extractTaskId(submitData);
  if (!taskId) {
    throw new Error("可灵视频接口未返回 task_id");
  }
  logger(`任务已提交，任务ID: ${taskId}`);

  const result = await pollTask(
    async () => {
      const taskData = await requestJson("GET", `${queryUrlBase}/${taskId}`, generateAuthToken(), undefined, 4);
      const status = extractTaskStatus(taskData);
      logger(`轮询中... 任务状态: ${status}`);

      const videoUrl = extractVideoResult(taskData);
      if (videoUrl) {
        return { completed: true, data: videoUrl };
      }
      if (["succeed", "success", "completed", "done"].includes(status)) {
        return { completed: true, error: "任务完成但未获取到视频URL" };
      }
      if (["failed", "failure", "error", "canceled", "cancelled"].includes(status)) {
        return { completed: false, error: extractTaskError(taskData) || "视频生成失败" };
      }

      return { completed: false };
    },
    3000,
    1800000,
  );

  if (result.error) throw new Error(result.error);
  logger(`视频生成完成，正在转换为Base64...`);
  return await urlToBase64(result.data!);
};

