  if (dataUrlMatch?.[0]) return dataUrlMatch[0];
  return null;
};

const extractImageValue = (payload: any): string | null => {
  if (!payload) return null;
  if (typeof payload === "string") {
    if (payload.startsWith("http") || payload.startsWith("//") || payload.startsWith("data:image")) {
      return payload.startsWith("//") ? `https:${payload}` : payload;
