  if (payload.image_url?.url) return payload.image_url.url;
  if (payload.url) return payload.url;
  if (payload.b64_json) return toDataImageUrl(payload.b64_json);
  if (payload.image) return extractImageValue(payload.image);
  if (payload.content) return extractImageValue(payload.content);
  if (payload.text) return extractImageValue(payload.text);
