const getHeaders = () => {
  if (!vendor.inputValues.apiKey) throw new Error("缺少API Key");
  return {
    "Content-Type": "application/json",
    Authorization: `Bearer ${vendor.inputValues.apiKey.replace(/^Bearer\s+/i, "")}`,
  };
};

const getBaseUrl = () => vendor.inputValues.baseUrl.replace(/\/+$/, "");

const MAX_VOLCENGINE_IMAGE_REFERENCE_BYTES = 1200 * 1024;
const MAX_VOLCENGINE_TOTAL_IMAGE_REFERENCE_BYTES = 4 * 1024 * 1024;
const MIN_VOLCENGINE_IMAGE_REFERENCE_BYTES = 400 * 1024;
const MAX_VOLCENGINE_BINARY_REFERENCE_BYTES = 5 * 1024 * 1024;

function getDataUrlBytes(value: string) {
  const body = String(value || "").split(",")[1] || "";
  const padding = body.match(/=+$/)?.[0]?.length || 0;
  return Math.max(0, Math.floor((body.length * 3) / 4) - padding);
}

function isDataUrl(value: string) {
  return /^data:/i.test(String(value || ""));
}

function getImageReferenceBudget(referenceCount: number) {
  if (referenceCount <= 0) return MAX_VOLCENGINE_IMAGE_REFERENCE_BYTES;
  return Math.max(
    MIN_VOLCENGINE_IMAGE_REFERENCE_BYTES,
    Math.min(MAX_VOLCENGINE_IMAGE_REFERENCE_BYTES, Math.floor(MAX_VOLCENGINE_TOTAL_IMAGE_REFERENCE_BYTES / referenceCount)),
  );
}

async function limitVolcengineImageReference(value: string, index: number, referenceCount: number) {
  if (!isDataUrl(value)) return value;
  const beforeBytes = getDataUrlBytes(value);
  const budget = getImageReferenceBudget(referenceCount);
  if (beforeBytes <= budget) return value;

  const nextValue = await zipImage(value, budget);
  const afterBytes = getDataUrlBytes(nextValue);
  logger(`火山参考图 ${index + 1} 请求体过大，已压缩：${beforeBytes} -> ${afterBytes} bytes`);
  return nextValue;
}

async function buildLimitedImageRefs(refs: Extract<ReferenceList, { type: "image" }>[]) {
  return Promise.all(
    refs.map(async (ref, index) => ({
      ...ref,
      base64: await limitVolcengineImageReference(ref.base64, index, refs.length),
    })),
  );
}

function filterLargeBinaryReferences<T extends { base64: string }>(refs: T[], typeLabel: string): T[] {
  return refs.filter((ref, index) => {
    if (!isDataUrl(ref.base64)) return true;
    const bytes = getDataUrlBytes(ref.base64);
    if (bytes <= MAX_VOLCENGINE_BINARY_REFERENCE_BYTES) return true;
    logger(`火山${typeLabel}${index + 1} 超过 ${MAX_VOLCENGINE_BINARY_REFERENCE_BYTES} bytes，已跳过以避免 413：${bytes} bytes`);
    return false;
  });
}

function getAxiosErrorText(error: any) {
  const data = error?.response?.data;
  return [
    error?.message,
    data?.error?.message,
    data?.message,
    data?.code,
    typeof data === "string" ? data : data ? JSON.stringify(data) : "",
  ]
    .filter(Boolean)
    .join(" ");
}

function isRealPersonImageError(error: any) {
  const text = getAxiosErrorText(error).toLowerCase();
  return text.includes("real person") || text.includes("真人");
}

function parseVideoMode(mode: any): any {
  if (typeof mode !== "string") return mode;
  const value = mode.trim();
  if (!value.startsWith("[")) return mode;
  try {
    return JSON.parse(value);
  } catch {
    return mode;
  }
}

function isReferenceModeToken(value: string) {
  return /^(textReference|imageReference|videoReference|audioReference)(:\d+)?$/.test(value);
}

function getScalarVideoModes(mode: any): string[] {
  const parsedMode = parseVideoMode(mode);
  if (typeof parsedMode === "string") return [parsedMode];
  if (!Array.isArray(parsedMode)) return [];
  return parsedMode.filter((item) => typeof item === "string" && !isReferenceModeToken(item));
}

function getReferenceModeTokens(mode: any): string[] {
  const parsedMode = parseVideoMode(mode);
  if (!Array.isArray(parsedMode)) return [];

  const directTokens = parsedMode.filter((item) => typeof item === "string" && isReferenceModeToken(item));
  if (directTokens.length > 0) return directTokens;

  for (const item of parsedMode) {
    if (!Array.isArray(item)) continue;
    const nestedTokens = item.filter((token) => typeof token === "string" && isReferenceModeToken(token));
    if (nestedTokens.length > 0) return nestedTokens;
  }
  return [];
}

function getReferenceLimit(tokens: string[], key: "imageReference" | "videoReference" | "audioReference", fallback: number) {
  const token = tokens.find((item) => item === key || item.startsWith(`${key}:`));
  if (!token) return 0;
  const rawLimit = token.includes(":") ? Number(token.split(":")[1]) : fallback;
  if (!Number.isFinite(rawLimit) || rawLimit <= 0) return fallback;
  return Math.min(Math.floor(rawLimit), fallback);
}

function filterVolcengineVideoReferences<T extends { base64: string }>(refs: T[]): T[] {
  return refs.filter((ref, index) => {
    const value = String(ref.base64 || "");
    if (/^(https?:\/\/|asset:\/\/)/i.test(value)) return true;
    logger(`火山视频参考${index + 1} 不是公网 URL 或 asset:// 素材 ID，已跳过。Seedance 2.0/2.0-Fast 不支持视频 base64 输入`);
    return false;
  });
}

function addImageContent(content: any[], refs: Extract<ReferenceList, { type: "image" }>[], role: "first_frame" | "last_frame" | "reference_image") {
  for (const ref of refs) {
    content.push({
      type: "image_url",
      image_url: { url: ref.base64 },
      role,
    });
  }
}

function addVideoContent(content: any[], refs: Extract<ReferenceList, { type: "video" }>[]) {
  for (const ref of refs) {
    content.push({
      type: "video_url",
      video_url: { url: ref.base64 },
      role: "reference_video",
    });
  }
}

function addAudioContent(content: any[], refs: Extract<ReferenceList, { type: "audio" }>[]) {
  for (const ref of refs) {
    content.push({
      type: "audio_url",
      audio_url: { url: ref.base64 },
      role: "reference_audio",
    });
  }
}

