const textRequest = (model: TextModel, think: boolean, thinkLevel: 0 | 1 | 2 | 3) => {
  if (!vendor.inputValues.apiKey) throw new Error("缺少API Key");
  const apiKey = vendor.inputValues.apiKey.replace(/^Bearer\s+/i, "");

  const effortMap: Record<number, string> = {
    0: "minimal",
    1: "low",
    2: "medium",
    3: "high",
  };

  return createOpenAICompatible({
    name: "volcengine",
    baseURL: getBaseUrl(),
    apiKey,
    fetch: async (url: string, options?: RequestInit) => {
      const rawBody = JSON.parse((options?.body as string) ?? "{}");
      const modifiedBody = {
        ...rawBody,
        thinking: {
          type: "enabled",
        },
        reasoning_effort: effortMap[thinkLevel],
      };
      return await fetch(url, {
        ...options,
        body: JSON.stringify(modifiedBody),
      });
    },
  }).chatModel(model.modelName);
};

const imageRequest = async (config: ImageConfig, model: ImageModel): Promise<string> => {
  const baseUrl = getBaseUrl();
  const headers = getHeaders();

  const body: any = {
    model: model.modelName,
    prompt: config.prompt || "",
    response_format: "url",
    watermark: false,
  };

  const isOldModel = model.modelName.includes("seedream-3-0");
  const is5Lite = model.modelName.includes("seedream-5-0-lite");

  // sequential_image_generation 仅 seedream 5.0-lite/4.5/4.0 支持
  if (!isOldModel) {
    body.sequential_image_generation = "disabled";
  }

  // 参考图片：单图为 string，多图为 array（seedream-3.0-t2i 不支持 image 参数）
  if (!isOldModel && config.referenceList && config.referenceList.length > 0) {
    const limitedRefs = await buildLimitedImageRefs(config.referenceList);
    const images = limitedRefs.map((ref) => ref.base64);
    body.image = images.length === 1 ? images[0] : images;
  }

  // 尺寸处理：优先使用推荐像素值，未匹配则直接传分辨率字符串让模型自行决定
  const [w, h] = config.aspectRatio.split(":").map(Number);
  const sizeTable: Record<string, Record<string, string>> = {
    "1K": {
      "1:1": "1024x1024",
      "4:3": "1152x864",
      "3:4": "864x1152",
      "16:9": "1280x720",
      "9:16": "720x1280",
      "3:2": "1248x832",
      "2:3": "832x1248",
      "21:9": "1512x648",
    },
    "2K": {
      "1:1": "2048x2048",
      "4:3": "2304x1728",
      "3:4": "1728x2304",
      "16:9": "2848x1600",
      "9:16": "1600x2848",
      "3:2": "2496x1664",
      "2:3": "1664x2496",
      "21:9": "3136x1344",
    },
    "4K": {
      "1:1": "4096x4096",
      "4:3": "4704x3520",
      "3:4": "3520x4704",
      "16:9": "5504x3040",
      "9:16": "3040x5504",
      "3:2": "4992x3328",
      "2:3": "3328x4992",
      "21:9": "6240x2656",
    },
  };

  const sizeKey = config.size || "2K";
  const ratioKey = config.aspectRatio;
  const table = sizeTable[sizeKey];

  if (table && table[ratioKey]) {
    // 推荐像素值匹配到了，但需要检查是否满足模型最低像素要求
    const [pw, ph] = table[ratioKey].split("x").map(Number);
    const totalPixels = pw * ph;
    if (isOldModel) {
      // seedream-3.0-t2i: 像素范围 [512x512, 2048x2048]
      body.size = table[ratioKey];
    } else if (totalPixels < 3686400) {
      // 1K 像素值不满足新模型最低要求，直接传 "2K" 让模型自行决定
      body.size = "2K";
    } else if (is5Lite && totalPixels > 10404496) {
      // seedream-5.0-lite 最高 10404496，4K 超限，回退传 "2K"
      body.size = "2K";
    } else {
      body.size = table[ratioKey];
    }
  } else if (isOldModel) {
    // seedream-3.0-t2i: 像素范围 [512x512, 2048x2048]，直接按比例计算
    const base = sizeKey === "1K" ? 1024 : 2048;
    const calcW = Math.min(2048, Math.round(base * Math.sqrt(w / h)));
    const calcH = Math.min(2048, Math.round(base * Math.sqrt(h / w)));
    body.size = `${Math.max(512, calcW)}x${Math.max(512, calcH)}`;
  } else {
    // 新模型未匹配推荐值时，直接传分辨率字符串（方式1），由模型根据 prompt 自行决定尺寸
    // seedream 5.0-lite 支持 "2K"/"3K"，seedream 4.5 支持 "2K"/"4K"，seedream 4.0 支持 "1K"/"2K"/"4K"
    if (is5Lite) {
      body.size = sizeKey === "4K" ? "3K" : sizeKey === "1K" ? "2K" : sizeKey;
    } else {
      body.size = sizeKey === "1K" ? "2K" : sizeKey;
    }
  }

  logger(`[图片生成] 请求模型: ${model.modelName}, 尺寸: ${body.size}`);

  const response = await axios.post(`${baseUrl}/images/generations`, body, { headers });
  const data = response.data;

  if (data?.error) {
    throw new Error(`图片生成失败：${data.error.message || data.error.code}`);
  }

  // 从 data 数组中提取第一张成功的图片
  if (data?.data && data.data.length > 0) {
    for (const item of data.data) {
      if (item.url) {
        return await urlToBase64(item.url);
      }
      if (item.b64_json) {
        return item.b64_json;
      }
      if (item.error) {
        throw new Error(`图片生成失败：${item.error.message || item.error.code}`);
      }
    }
  }

  throw new Error("图片生成失败：未返回有效结果");
};

const videoRequest = async (config: VideoConfig, model: VideoModel): Promise<string> => {
  const baseUrl = getBaseUrl();
  const headers = getHeaders();

  const content: any[] = [];

  if (config.prompt) {
    content.push({ type: "text", text: config.prompt });
  }

  const allReferences = config.referenceList ?? [];
  const imageRefs = await buildLimitedImageRefs(allReferences.filter((r) => r.type === "image") as Extract<ReferenceList, { type: "image" }>[]);
  const videoRefs = filterLargeBinaryReferences(
    allReferences.filter((r) => r.type === "video") as Extract<ReferenceList, { type: "video" }>[],
    "视频参考",
  );
  const audioRefs = filterLargeBinaryReferences(
    allReferences.filter((r) => r.type === "audio") as Extract<ReferenceList, { type: "audio" }>[],
    "音频参考",
  );

  const referenceModeTokens = getReferenceModeTokens(config.mode);
  if (referenceModeTokens.length > 0) {
    const imageLimit = getReferenceLimit(referenceModeTokens, "imageReference", 9);
    const videoLimit = getReferenceLimit(referenceModeTokens, "videoReference", 3);
    const audioLimit = getReferenceLimit(referenceModeTokens, "audioReference", 3);

    addImageContent(content, imageRefs.slice(0, imageLimit), "reference_image");
    addVideoContent(content, filterVolcengineVideoReferences(videoRefs).slice(0, videoLimit));

    const hasVisualReference = content.some((item) => item.type === "image_url" || item.type === "video_url");
    if (hasVisualReference) {
      addAudioContent(content, audioRefs.slice(0, audioLimit));
    } else if (audioLimit > 0 && audioRefs.length > 0) {
      logger("火山音频参考需要至少 1 个图片或视频参考，当前没有有效视觉参考，已跳过音频参考");
    }
  } else {
    const scalarModes = getScalarVideoModes(config.mode);
    const mode = scalarModes[0] || "text";
    switch (mode) {
      case "singleImage":
        addImageContent(content, imageRefs.slice(0, 1), "first_frame");
        break;
      case "startFrameOptional":
      case "endFrameOptional":
        addImageContent(content, imageRefs.slice(0, 1), "first_frame");
        if (imageRefs.length > 1) addImageContent(content, imageRefs.slice(1, 2), "last_frame");
        break;
      case "startEndRequired":
        if (imageRefs.length >= 2) {
          addImageContent(content, imageRefs.slice(0, 1), "first_frame");
          addImageContent(content, imageRefs.slice(1, 2), "last_frame");
        }
        break;
      case "text":
      default:
        break;
    }
  }

  const body: any = {
    model: model.modelName,
    content,
    ratio: config.aspectRatio,
    duration: config.duration,
    resolution: config.resolution || "720p",
    watermark: false,
  };

  if (model.audio === "optional") {
    body.generate_audio = config.audio !== false;
  } else if (model.audio === true) {
    body.generate_audio = true;
  } else {
    body.generate_audio = false;
  }

  const contentSummary = content.reduce<Record<string, number>>((acc, item) => {
    acc[item.type] = (acc[item.type] || 0) + 1;
    return acc;
  }, {});
  logger(`[视频生成] 提交任务, 模型: ${model.modelName}, 时长: ${config.duration}s, 分辨率: ${config.resolution}, 内容: ${JSON.stringify(contentSummary)}`);

  let createResponse: any;
  try {
    createResponse = await axios.post(`${baseUrl}/contents/generations/tasks`, body, { headers });
  } catch (error) {
    const hasImageInput = content.some((item) => item.type === "image_url");
    if (!hasImageInput || !isRealPersonImageError(error)) throw error;

    logger("[视频生成] 火山返回输入图片可能包含真人，已改用纯文本提示词重试");
    body.content = content.filter((item) => item.type === "text");
    createResponse = await axios.post(`${baseUrl}/contents/generations/tasks`, body, { headers });
  }
  const taskId = createResponse.data?.id;

  if (!taskId) {
    throw new Error("视频生成任务创建失败：未返回任务ID");
  }

  logger(`[视频生成] 任务已创建, ID: ${taskId}`);

  const result = await pollTask(
    async (): Promise<PollResult> => {
      const queryResponse = await axios.get(`${baseUrl}/contents/generations/tasks/${taskId}`, { headers });
      const task = queryResponse.data;

      logger(`[视频生成] 任务状态: ${task.status}`);

      switch (task.status) {
        case "succeeded":
          if (task.content?.video_url) {
            return { completed: true, data: task.content.video_url };
          }
          return { completed: true, error: "任务成功但未返回视频URL" };
        case "failed":
          return { completed: true, error: task.error?.message || "视频生成失败" };
        case "expired":
          return { completed: true, error: "视频生成任务超时" };
        case "cancelled":
          return { completed: true, error: "视频生成任务已取消" };
        default:
          return { completed: false };
      }
    },
    10000,
    600000,
  );

  if (result.error) {
    throw new Error(result.error);
  }

  return await urlToBase64(result.data!);
};

